'use strict';
const https = require('https');
const crypto = require('crypto');

function buildAuthUrl(config) {
  const { clientId, redirectUri, authEndpoint, scopes = [], state } = config;
  const params = new URLSearchParams({
    response_type: 'code',
    client_id: clientId,
    redirect_uri: redirectUri,
    scope: scopes.join(' '),
    state: state || crypto.randomBytes(16).toString('hex'),
  });
  return authEndpoint + '?' + params.toString();
}

function exchangeCode(config) {
  const { code, clientId, clientSecret, redirectUri, tokenEndpoint } = config;
  const body = new URLSearchParams({
    grant_type: 'authorization_code', code, client_id: clientId,
    client_secret: clientSecret, redirect_uri: redirectUri,
  }).toString();
  return postForm(tokenEndpoint, body);
}

function refreshToken(config) {
  const { refreshToken: token, clientId, clientSecret, tokenEndpoint } = config;
  const body = new URLSearchParams({
    grant_type: 'refresh_token', refresh_token: token,
    client_id: clientId, client_secret: clientSecret,
  }).toString();
  return postForm(tokenEndpoint, body);
}

function postForm(endpoint, body) {
  return new Promise((resolve, reject) => {
    const url = new URL(endpoint);
    const req = https.request({
      hostname: url.hostname, port: url.port || 443, path: url.pathname,
      method: 'POST',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded', 'Content-Length': Buffer.byteLength(body) },
    }, (res) => {
      let data = '';
      res.on('data', c => data += c);
      res.on('end', () => {
        try { resolve(JSON.parse(data)); } catch { reject(new Error('Invalid response')); }
      });
    });
    req.on('error', reject);
    req.write(body);
    req.end();
  });
}

module.exports = { buildAuthUrl, exchangeCode, refreshToken };

