'use strict';
const crypto = require('crypto');

function verifySignature(payload, signature, secret, algorithm = 'sha256') {
  const expected = crypto.createHmac(algorithm, secret).update(payload).digest('hex');
  const sig = signature.replace(/^sha256=/, '');
  return crypto.timingSafeEqual(Buffer.from(expected, 'hex'), Buffer.from(sig, 'hex'));
}

function checkReplay(timestamp, maxAgeSeconds = 300) {
  const ts = typeof timestamp === 'number' ? timestamp : parseInt(timestamp, 10);
  if (isNaN(ts)) return false;
  const now = Math.floor(Date.now() / 1000);
  return Math.abs(now - ts) <= maxAgeSeconds;
}

function createWebhookHandler(config) {
  const { secret, maxAgeSeconds = 300, signatureHeader = 'x-hub-signature-256', timestampHeader = 'x-webhook-timestamp' } = config;
  const processed = new Set();

  return function handleWebhook(req) {
    const { headers, body, id } = req;
    const signature = headers[signatureHeader];
    if (!signature) return { valid: false, error: 'Missing signature header' };

    const rawBody = typeof body === 'string' ? body : JSON.stringify(body);
    if (!verifySignature(rawBody, signature, secret)) {
      return { valid: false, error: 'Invalid signature' };
    }

    const timestamp = headers[timestampHeader];
    if (timestamp && !checkReplay(timestamp, maxAgeSeconds)) {
      return { valid: false, error: 'Replay detected or expired' };
    }

    if (id && processed.has(id)) {
      return { valid: false, error: 'Duplicate delivery' };
    }
    if (id) { processed.add(id); if (processed.size > 10000) processed.clear(); }

    return { valid: true, payload: typeof body === 'string' ? JSON.parse(body) : body };
  };
}

module.exports = { verifySignature, checkReplay, createWebhookHandler };

