'use strict';
const fs = require('fs');
const path = require('path');

class MigrationRunner {
  constructor(db, migrationsDir) {
    this._db = db;
    this._dir = migrationsDir;
    this._ensureTable();
  }

  _ensureTable() {
    this._db.exec('CREATE TABLE IF NOT EXISTS migrations (version TEXT PRIMARY KEY, applied_at TEXT NOT NULL, name TEXT)');
  }

  _applied() {
    return this._db.prepare('SELECT version FROM migrations ORDER BY version').all().map(r => r.version);
  }

  _migrations() {
    if (!fs.existsSync(this._dir)) return [];
    return fs.readdirSync(this._dir)
      .filter(f => f.match(/^d+.*.(js|sql)$/))
      .sort()
      .map(f => ({ version: f.split('_')[0], name: f, path: path.join(this._dir, f) }));
  }

  pending() {
    const applied = new Set(this._applied());
    return this._migrations().filter(m => !applied.has(m.version));
  }

  up(steps = Infinity) {
    const pending = this.pending().slice(0, steps);
    const results = [];
    for (const migration of pending) {
      const content = fs.readFileSync(migration.path, 'utf-8');
      if (migration.name.endsWith('.sql')) {
        this._db.exec(content);
      } else {
        const mod = require(migration.path);
        if (typeof mod.up === 'function') mod.up(this._db);
      }
      this._db.prepare('INSERT INTO migrations (version, applied_at, name) VALUES (?, ?, ?)').run(migration.version, new Date().toISOString(), migration.name);
      results.push(migration.name);
    }
    return { applied: results.length, migrations: results };
  }

  down(steps = 1) {
    const applied = this._applied().reverse().slice(0, steps);
    const results = [];
    for (const version of applied) {
      const migration = this._migrations().find(m => m.version === version);
      if (migration && migration.name.endsWith('.js')) {
        const mod = require(migration.path);
        if (typeof mod.down === 'function') mod.down(this._db);
      }
      this._db.prepare('DELETE FROM migrations WHERE version = ?').run(version);
      results.push(version);
    }
    return { rolled_back: results.length, versions: results };
  }

  status() {
    return { applied: this._applied().length, pending: this.pending().length, total: this._migrations().length };
  }
}

module.exports = { MigrationRunner };

