'use strict';

class CacheWrapper {
  constructor(client, options = {}) {
    this._client = client;
    this._prefix = options.prefix || '';
    this._defaultTtl = options.defaultTtl || 3600;
  }

  _key(key) { return this._prefix ? this._prefix + ':' + key : key; }

  async get(key) {
    const raw = await this._client.get(this._key(key));
    if (raw === null || raw === undefined) return null;
    try { return JSON.parse(raw); } catch { return raw; }
  }

  async set(key, value, ttl) {
    const serialized = JSON.stringify(value);
    const seconds = ttl || this._defaultTtl;
    if (seconds > 0) {
      await this._client.setex(this._key(key), seconds, serialized);
    } else {
      await this._client.set(this._key(key), serialized);
    }
  }

  async del(key) { await this._client.del(this._key(key)); }

  async getOrSet(key, fetchFn, ttl) {
    const cached = await this.get(key);
    if (cached !== null) return cached;
    const value = await fetchFn();
    await this.set(key, value, ttl);
    return value;
  }

  async mget(keys) {
    const prefixed = keys.map(k => this._key(k));
    const values = await this._client.mget(prefixed);
    return values.map(v => { try { return JSON.parse(v); } catch { return v; } });
  }

  async flush() { if (this._prefix) { /* scan and delete prefix keys */ } }
}

module.exports = { CacheWrapper };

